import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';
import Dashboard from './Dashboard';
import { submitManualData } from './api';

function App() {
    const [user, setUser] = useState(null);
    const [view, setView] = useState('choice'); 
    const [isLoading, setIsLoading] = useState(false);
    
    // Data States
    const [analysisData, setAnalysisData] = useState(null);
    const [productName, setProductName] = useState('');
    const [dietHistory, setDietHistory] = useState([]);

    // Form States
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [barcode, setBarcode] = useState('');
    const [manualEntry, setManualEntry] = useState({ name: '', sugar: '', protein: '', fat: '' });

    useEffect(() => {
        supabase.auth.getSession().then(({ data: { session } }) => setUser(session?.user ?? null));
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => setUser(session?.user ?? null));
        return () => subscription.unsubscribe();
    }, []);

    // --- FETCH DIET PLAN ---
    const fetchDietPlan = async () => {
        setIsLoading(true);
        const { data, error } = await supabase
            .from('diet_logs')
            .select('*')
            .order('created_at', { ascending: false });
        
        if (!error) setDietHistory(data);
        setView('view_plan');
        setIsLoading(false);
    };

    // --- SAVE LOGIC ---
    const saveToDietPlan = async (customData = null) => {
        const entry = customData || {
            product_name: productName,
            analysis_json: analysisData,
            user_id: user.id
        };
        const { error } = await supabase.from('diet_logs').insert([entry]);
        if (error) alert(error.message);
        else {
            alert("Added to plan!");
            fetchDietPlan(); // Refresh and show plan
        }
    };

    const handleManualLog = () => {
        const custom = {
            product_name: manualEntry.name,
            user_id: user.id,
            analysis_json: [
                { rsid: `Sugar: ${manualEntry.sugar}g`, trait: "Nutrition", genotype: "Manual", recommendation: "Logged manually." },
                { rsid: `Protein: ${manualEntry.protein}g`, trait: "Nutrition", genotype: "Manual", recommendation: "Logged manually." },
                { rsid: `Fat: ${manualEntry.fat}g`, trait: "Nutrition", genotype: "Manual", recommendation: "Logged manually." }
            ]
        };
        saveToDietPlan(custom);
    };

    // --- UI COMPONENTS ---
    const MenuCard = ({ icon, title, desc, onClick }) => (
        <div style={styles.optionCard} onClick={onClick}>
            <div style={styles.cardIcon}>{icon}</div>
            <div style={styles.cardContent}>
                <h3 style={styles.cardTitle}>{title}</h3>
                <p style={styles.cardDesc}>{desc}</p>
            </div>
        </div>
    );

    if (!user) {
        return (
            <div style={styles.container}>
                <h1 style={styles.logoText}>NutriGen<span style={{color: '#38a169'}}>.</span></h1>
                <div style={styles.authCard}>
                    <input style={styles.input} placeholder="Email" onChange={e => setEmail(e.target.value)} />
                    <input style={styles.input} type="password" placeholder="Password" onChange={e => setPassword(e.target.value)} />
                    <button style={styles.primaryBtn} onClick={() => setView('login')}>Login</button>
                </div>
            </div>
        );
    }

    return (
        <div style={styles.container}>
            <header style={styles.nav}>
                <h1 style={styles.logoText} onClick={() => setView('choice')}>NutriGen.</h1>
                <button onClick={() => supabase.auth.signOut()} style={styles.logoutBtn}>Logout</button>
            </header>

            <main>
                {analysisData ? (
                    <div style={styles.resultsHeader}>
                        <h2 style={styles.productTitle}>{productName}</h2>
                        <div style={{display: 'flex', gap: '10px'}}>
                            <button style={styles.primaryBtn} onClick={() => saveToDietPlan()}>Add to Plan</button>
                            <button style={styles.secondaryBtn} onClick={() => setAnalysisData(null)}>Discard</button>
                        </div>
                        <Dashboard data={analysisData} onReset={() => setAnalysisData(null)} />
                    </div>
                ) : view === 'choice' ? (
                    <div style={styles.menuGrid}>
                        <MenuCard icon="🔍" title="Barcode Search" desc="Scan or enter a barcode to fetch global nutritional data instantly." onClick={() => setView('scan')} />
                        <MenuCard icon="📅" title="My Diet Plan" desc="View your logged meals and track your nutritional history." onClick={fetchDietPlan} />
                        <MenuCard icon="🧬" title="Health Quiz" desc="Answer a few questions to get personalized dietary recommendations." onClick={() => setView('quiz')} />
                    </div>
                ) : view === 'view_plan' ? (
                    <div style={styles.planView}>
                        <div style={styles.planHeader}>
                            <h2>Current Diet Plan</h2>
                            <button style={styles.primaryBtn} onClick={() => setView('manual_log')}>+ Add Manual Item</button>
                        </div>
                        {dietHistory.map(item => (
                            <div key={item.id} style={styles.historyItem}>
                                <strong>{item.product_name}</strong>
                                <span style={{color: '#666', fontSize: '0.8rem'}}> — {new Date(item.created_at).toLocaleDateString()}</span>
                            </div>
                        ))}
                        <button style={styles.backBtn} onClick={() => setView('choice')}>← Back to Menu</button>
                    </div>
                ) : view === 'manual_log' ? (
                    <div style={styles.card}>
                        <h3>Manual Nutritional Entry</h3>
                        <p style={styles.cardDesc}>Provide the details for an item not found in the database.</p>
                        <input style={styles.input} placeholder="Item Name" onChange={e => setManualEntry({...manualEntry, name: e.target.value})} />
                        <div style={styles.flexRow}>
                            <input style={styles.input} type="number" placeholder="Sugar (g)" onChange={e => setManualEntry({...manualEntry, sugar: e.target.value})} />
                            <input style={styles.input} type="number" placeholder="Protein (g)" onChange={e => setManualEntry({...manualEntry, protein: e.target.value})} />
                        </div>
                        <button style={styles.primaryBtn} onClick={handleManualLog}>Log to Diet Plan</button>
                        <button style={styles.backBtn} onClick={() => setView('view_plan')}>Cancel</button>
                    </div>
                ) : view === 'scan' ? (
                    <div style={styles.card}>
                        <h3>Product Scanner</h3>
                        <p style={styles.cardDesc}>Upload a photo of a barcode or type the number below.</p>
                        <input style={styles.input} placeholder="Enter Barcode" onChange={e => setBarcode(e.target.value)} />
                        <button style={styles.primaryBtn} onClick={() => handleBarcodeSearch(barcode)}>Analyze Product</button>
                        <button style={styles.backBtn} onClick={() => setView('choice')}>Cancel</button>
                    </div>
                ) : null}
            </main>
        </div>
    );
}

